const MIME_BY_EXTENSION = {
  pdf: 'application/pdf',
  doc: 'application/msword',
  docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  rtf: 'application/rtf',
};

const TEXT_AS_PLAIN_EXTENSIONS = new Set([
  'txt', 'text', 'md', 'markdown', 'rst', 'adoc', 'asciidoc', 'tex',
  'json', 'jsonl', 'json5', 'yaml', 'yml', 'toml', 'ini', 'cfg', 'conf', 'env', 'properties',
  'xml', 'csv', 'tsv', 'psv', 'ssv',
  'html', 'htm', 'xhtml', 'svg',
  'js', 'mjs', 'cjs', 'jsx', 'ts', 'tsx', 'vue', 'svelte',
  'py', 'pyi', 'java', 'kt', 'kts', 'scala', 'groovy',
  'c', 'h', 'cpp', 'cc', 'cxx', 'hpp', 'hh', 'hxx',
  'cs', 'go', 'rs', 'rb', 'php', 'swift', 'm', 'mm', 'dart', 'lua', 'r', 'jl', 'pl', 'pm',
  'sh', 'bash', 'zsh', 'fish', 'ps1', 'bat', 'cmd', 'awk', 'sed',
  'sql', 'graphql', 'gql', 'proto',
  'log', 'out', 'err',
  'gitignore', 'gitattributes', 'npmrc', 'yarnrc', 'editorconfig', 'dockerignore',
  'ipynb'
]);

const TEXT_FILENAME_HINTS = new Set([
  'dockerfile', 'makefile', 'jenkinsfile', 'procfile', 'vagrantfile', 'gemfile', 'rakefile',
  '.env', '.env.local', '.env.development', '.env.test', '.env.production',
  '.gitignore', '.gitattributes', '.npmrc', '.yarnrc', '.editorconfig'
]);

function resolveMimeType(itemJson, entry) {
  const ext = String(itemJson?.extension || entry?.fileExtension || '').toLowerCase();
  const fileName = String(itemJson?.fileName || entry?.fileName || '').toLowerCase();
  const incoming = String(entry?.mimeType || '').toLowerCase();

  if (MIME_BY_EXTENSION[ext]) return MIME_BY_EXTENSION[ext];
  if (TEXT_AS_PLAIN_EXTENSIONS.has(ext)) return 'text/plain';
  if (TEXT_FILENAME_HINTS.has(fileName)) return 'text/plain';

  if (incoming.startsWith('text/')) return 'text/plain';
  if (
    incoming.includes('json')
    || incoming.includes('xml')
    || incoming.includes('yaml')
    || incoming.includes('toml')
    || incoming.includes('csv')
    || incoming.includes('javascript')
    || incoming.includes('typescript')
    || incoming.includes('sql')
    || incoming.includes('markdown')
  ) {
    return 'text/plain';
  }

  return String(entry?.mimeType || 'application/octet-stream');
}

const items = $input.all();
const out = [];
const getBinaryDataBufferHelper = this?.helpers?.getBinaryDataBuffer?.bind(this.helpers);

for (let index = 0; index < items.length; index++) {
  const item = items[index];
  const entry = item.binary?.data ?? Object.values(item.binary ?? {})[0] ?? null;
  let buffer = Buffer.alloc(0);

  if (typeof getBinaryDataBufferHelper === 'function') {
    try {
      buffer = (await getBinaryDataBufferHelper(index, 'data')) || Buffer.alloc(0);
    } catch (error) {
      buffer = Buffer.alloc(0);
    }
  }

  if ((!buffer || buffer.length === 0) && entry?.data && entry.data !== 'filesystem-v2') {
    try {
      buffer = Buffer.from(String(entry.data), 'base64');
    } catch (error) {
      buffer = Buffer.alloc(0);
    }
  }

  if (!buffer || buffer.length === 0) {
    throw new Error('Missing binary payload for OCR preparation: ' + String(item.json?.fileName || ('item_' + index)));
  }

  const resolvedMimeType = resolveMimeType(item.json ?? {}, entry ?? {});

  out.push({
    json: { ...(item.json ?? {}), extractionMethod: 'mistral_ocr' },
    binary: {
      data: {
        ...(entry ?? {}),
        mimeType: resolvedMimeType,
        data: buffer.toString('base64'),
      },
    },
    pairedItem: item.pairedItem ?? { item: index },
  });
}

return out;
